(window.webpackJsonp=window.webpackJsonp||[]).push([[16],{497:function(n,o,e){"use strict";e.r(o);var t=e(4),a=Object(t.a)({},(function(){var n=this.$createElement,o=this._self._c||n;return o("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[o("h1",{attrs:{id:"mongo常用命令"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#mongo常用命令"}},[this._v("#")]),this._v(" mongo常用命令")]),this._v(" "),o("div",{staticClass:"language- extra-class"},[o("pre",{pre:!0,attrs:{class:"language-text"}},[o("code",[this._v('Mongo基本命令\n1、启动\n\n　纯命令：mongod --dbpath=/opt/michael/mongodb/mongodb-linux-x86_64-4.0.5/data --bind_ip=0.0.0.0\n\n　可以将命令行参数写入配置文件，然后通过配置文件的方式启动\n\n　这里在mongodb目录下新建config/mongodb.cfg，文件内容如下：\n\n　dbpath=/opt/michael/mongodb/mongodb-linux-x86_64-4.0.5/data\n　logpath=/opt/michael/mongodb/mongodb-linux-x86_64-4.0.5/logs/mongodb.log\n　fork=true\n　logappend=true\n　bind_ip=0.0.0.0\n\n \n　然后，通过命令mongod -f /opt/michael/mongodb/mongodb-linux-x86_64-4.0.5/config/mongodb.cfg命令启动，需要设置的参数信息都放置在配置文件中。\n\n2、客户端连接\n\n　　mongo       连接本机\n\n　　mongo ip   连接远程服务\n\n3、查询数据库\n\n　　show dbs\n\n　　或\n\n　　show databases\n\n4、创建数据库\n\n　　use dbName\n\n　　查看表\n\n　　show tables;\n\n5、插入数据\n\n　　db.<tableName>.insert();\n\n　　如：db.members.insert({name:"Michael",age:18,...});\n\n6、查询\n\n　　db.<tableName>.find();\n\n7、修改\n\n　　如：db.members.update({name:"Michael"},{$set:{age:20}});\n\n8、删除表中的数据\n\n　　如：db.members.remove({name:"Michael"});\n\n　　删除全部：db.members.remove({});\n\n9、删除表\n\n　　db.members.drop();\n\n10、删除数据库\n\n　　db.dropDatabase();\n')])])])])}),[],!1,null,null,null);o.default=a.exports}}]);